// =====================================================
// ANALISADOR DE MÉTRICAS N8N - CHATBOT TINTAS MC
// =====================================================

// ===== CONFIGURAÇÕES =====
const MINUTOS_POR_MSG_BOT = 3;   // Tempo economizado por resposta do bot
const TZ_OFFSET_MIN = -180;      // São Paulo UTC-3 (em minutos)
const HORA_INICIO = 8;           // Abertura da loja (ajustado para 8h conforme solicitado)
const HORA_FIM = 18;             // Fechamento da loja

// ===== HELPERS DE FORMATAÇÃO =====
const nf = new Intl.NumberFormat('pt-BR');
const pct = (n, d) => d ? Math.round((n / d) * 100) : 0;
const currency = (value) => new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL'
}).format(value);

function toLocalHour(isoOrNull) {
  if (!isoOrNull) return null;
  const d = new Date(isoOrNull);
  const minLocal = (d.getUTCHours() * 60 + d.getUTCMinutes() + TZ_OFFSET_MIN + 1440) % 1440;
  return Math.floor(minLocal / 60);
}

function formatTime(minutes) {
  const hours = Math.floor(minutes / 60);
  const mins = Math.round(minutes % 60);
  if (hours > 24) {
    const days = Math.floor(hours / 24);
    const remainingHours = hours % 24;
    return `${days} dias e ${remainingHours}h`;
  }
  return hours > 0 ? `${hours}h ${mins}min` : `${mins} minutos`;
}

// ===== PROCESSAMENTO DOS DADOS =====
const conv = new Map();
let totalMensagens = 0;
let totalBot = 0;
let totalUser = 0;
let mensagensAntes8 = 0;  // Ajustado para 8h
let mensagensApos18 = 0;

// Análise adicional
let conversasComOrcamento = 0;
let conversasComProdutos = 0;
let horariosAtendimento = [];

for (const it of items) {
  const j = it.json || {};
  const cid = j.conversation_id;
  if (!cid) continue;

  if (!conv.has(cid)) {
    conv.set(cid, { 
      msgsTotais: 0, 
      msgsBot: 0, 
      msgsUser: 0, 
      antes8: false,  // Ajustado
      apos18: false,
      temOrcamento: false,
      temProduto: false,
      telefone: j.phone,
      loja: j.loja || 'Não especificada'
    });
  }
  const c = conv.get(cid);

  const hasUser = !!(j.user_message && String(j.user_message).trim());
  const hasBot = !!(j.bot_message && String(j.bot_message).trim());

  // Análise de conteúdo
  const msgContent = (j.bot_message || '') + ' ' + (j.user_message || '');
  if (msgContent.toLowerCase().includes('orçamento') || msgContent.includes('R$')) {
    c.temOrcamento = true;
  }
  if (msgContent.toLowerCase().match(/tinta|lixa|rolo|pincel|suvinil|coral/)) {
    c.temProduto = true;
  }

  if (hasUser) {
    totalMensagens++;
    totalUser++;
    c.msgsTotais++;
    c.msgsUser++;
  }
  if (hasBot) {
    totalMensagens++;
    totalBot++;
    c.msgsTotais++;
    c.msgsBot++;
  }

  // Análise de horário
  const h = toLocalHour(j.updated_at || j.created_at);
  if (h !== null) {
    horariosAtendimento.push(h);
    if (h < HORA_INICIO) {
      mensagensAntes8++;
      c.antes8 = true;
    } else if (h >= HORA_FIM) {
      mensagensApos18++;
      c.apos18 = true;
    }
  }
}

// ===== CÁLCULO DE MÉTRICAS =====
const totalAtendimentos = conv.size;
const mediaMsgsPorAtendimento = totalAtendimentos ? (totalMensagens / totalAtendimentos) : 0;
const participacaoIA = (totalBot + totalUser) ? Math.round((totalBot / (totalBot + totalUser)) * 100) : 0;

const tempoEconomizadoMinutos = totalBot * MINUTOS_POR_MSG_BOT;
const tempoEconomizadoHoras = tempoEconomizadoMinutos / 60;
const jornadas8h = tempoEconomizadoMinutos / 480;

// Valor economizado (baseado em custo médio de atendente)
const CUSTO_HORA_ATENDENTE = 15; // R$ 15/hora (estimativa)
const valorEconomizado = tempoEconomizadoHoras * CUSTO_HORA_ATENDENTE;

// Contagem de atendimentos fora do horário
let atendimentosAntes8 = 0;
let atendimentosApos18 = 0;
for (const c of conv.values()) {
  if (c.antes8) atendimentosAntes8++;
  if (c.apos18) atendimentosApos18++;
  if (c.temOrcamento) conversasComOrcamento++;
  if (c.temProduto) conversasComProdutos++;
}
const atendimentosForaHorario = atendimentosAntes8 + atendimentosApos18;
const percentualForaHorario = pct(atendimentosForaHorario, totalAtendimentos);

// Análise de pico de horário
const picoHorario = horariosAtendimento.reduce((acc, h) => {
  acc[h] = (acc[h] || 0) + 1;
  return acc;
}, {});
const horarioMaisBuscado = Object.entries(picoHorario).sort((a, b) => b[1] - a[1])[0];

// ===== GERAÇÃO DO HTML CRIATIVO =====
const geradoEm = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const html = `
