`;

// ===== RETORNO PARA O N8N =====
return [
  {
    json: {
      // Métricas solicitadas
      totalAtendimentos,
      totalMensagens,
      mensagensBot: totalBot,
      mensagensUsuario: totalUser,
      mediaMensagensPorAtendimento: mediaMsgsPorAtendimento.toFixed(2),
      tempoEconomizadoMinutos,
      tempoEconomizadoHoras: tempoEconomizadoHoras.toFixed(1),
      minutosPorMensagemBot: MINUTOS_POR_MSG_BOT,
      atendimentosForaHorario,
      percentualForaHorario,
      atendimentosAntes8,
      atendimentosApos18,
      mensagensAntes8,
      mensagensApos18,

      // Métricas adicionais úteis
      participacaoIAPercentual: participacaoIA,
      jornadasEconomizadas: jornadas8h.toFixed(1),
      valorEconomizado: valorEconomizado.toFixed(2),
      conversasComOrcamento,
      conversasComProdutos,
      horarioPico: horarioMaisBuscado ? `${horarioMaisBuscado[0]}h` : 'N/A',

      // HTML do relatório
      html,

      // Metadados
      geradoEm,
      fusoHorario: 'America/Sao_Paulo (UTC-3)',
      versao: '2.0'
    }
  }
];

const registros = items.map(i => i.json);

const alvo = "ola! vi a tintas mc em um anuncio e gostaria de mais informacoes";

// normalizador
const norm = s => String(s || '')
  .normalize("NFD")
  .replace(/[\u0300-\u036f]/g, "")
  .toLowerCase()
  .trim();

// função para formatar data no padrão brasileiro dd/mm/aaaa
const formatDate = iso => {
  if (!iso) return "";
  const d = new Date(iso);
  const dia = String(d.getDate()).padStart(2, "0");
  const mes = String(d.getMonth() + 1).padStart(2, "0");
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
};

// total de mensagens no supabase (sem filtro)
const total_mensagens = registros.length;

// filtra mensagens que contenham o alvo
const filtrados = registros.filter(r => norm(r.user_message).includes(alvo));

// contatos com data formatada
const contatos = filtrados.map(r => ({
  telefone: r.phone,
  data: formatDate(r.created_at)
}));

// saída
return [
  {
    json: {
      total_mensagens,
      total_ocorrencias: filtrados.length,
      contatos
    }
  }
];

const dados = items[0].json;

const totalMensagens = dados.total_mensagens || 0;
const totalOcorrencias = dados.total_ocorrencias || 0;
const contatos = dados.contatos || [];

const percentual = totalMensagens > 0 
  ? ((totalOcorrencias / totalMensagens) * 100).toFixed(1) 
  : "0";

// monta lista de contatos
const listaContatos = contatos.map(c => `- ${c.data} — ${c.telefone}`).join("\n");

// mensagem final
const mensagem = 
`📊 Relatório de Conversas — Fonte Tráfego Pago

No período analisado, tivemos **${totalMensagens} conversas iniciadas** no WhatsApp da Tintas MC.  
Destas, **${totalOcorrencias} conversas (≈${percentual}%)** começaram a partir da mensagem de tráfego:  
*"Olá! Vi a Tintas MC em um anúncio e gostaria de mais informações."*

Isso significa que, de cada 100 conversas abertas, apenas ${percentual} vieram diretamente do anúncio.  
Esses contatos são rastreáveis e permitem medir com clareza o impacto da campanha de marketing.

📌 Lista de contatos que iniciaram via anúncio:
${listaContatos}`;

return [{ json: { mensagem } }];
